stageContent:
steps {
  script {
    echo "========== 环境变量 =========="
    echo "APP_NAME = ${env.APP_NAME}"
    echo "BUILD_TIMESTAMP = ${env.BUILD_TIMESTAMP}"
    echo "FULL_APP_NAME = ${env.FULL_APP_NAME}"
    // 凭据中的用户名（注意不要打印密码）
    echo "Docker 用户名: ${env.DOCKER_CREDS_USR}"

    echo "\n========== 构建参数 =========="
    echo "VERSION = ${params.VERSION}"
    echo "RELEASE_NOTES = ${params.RELEASE_NOTES}"
    echo "SKIP_TESTS = ${params.SKIP_TESTS}"
    echo "ENVIRONMENT = ${params.ENVIRONMENT}"
    // 密码参数不直接打印值，只打印长度
    def tokenLen = params.API_TOKEN ? params.API_TOKEN.length() : 0
    echo "API_TOKEN 长度 = ${tokenLen} (实际值不会打印)"

    // 文件参数：会生成一个临时路径，指向用户上传的文件
    if (params.CONFIG_FILE) {
      echo "上传的配置文件路径: ${params.CONFIG_FILE}"
      // 可以读取文件内容并进行处理
      def fileContent = readFile(params.CONFIG_FILE)
      echo "文件内容预览: ${fileContent.take(100)}"
    } else {
    echo "未上传配置文件"
  }

// run 参数：获取的是所选构建的编号
if (params.BASE_BUILD) {
  echo "选中的上游构建号: ${params.BASE_BUILD}"
}
}
}

steps {
  script {
    // 获取当前任务名
    def jobName = env.JOB_BASE_NAME ?: (env.JOB_NAME ?: 'unknown-job').tokenize('/').last()

    // 获取用户传入的根目录，如果没有则默认为 JENKINS_HOME
    def baseCacheDir = params.NPM_CACHE_DIR?.trim()
    if (!baseCacheDir) {
      baseCacheDir = env.JENKINS_HOME
    }

    // 统一拼接子路径，确保一定包含 jobName
    def resolvedCacheDir = "${baseCacheDir}/npm-build-cache/${jobName}"

    // 调用共享库，传入所有配置参数
    def result = npmBuildProject(
      // 基础参数
      targetDir              : params.NPM_TARGET_DIR,
      timeoutMinutes         : params.NPM_TIMEOUT_MINUTES,
      outputDir              : params.NPM_OUTPUT_DIR,

      // 命令
      installCommand         : params.NPM_INSTALL_COMMAND,
      buildCommand           : params.NPM_BUILD_COMMAND,

      // 缓存
      cacheEnabled           : params.NPM_CACHE_ENABLED,
      npmCacheDir            : resolvedCacheDir,
      cleanCacheBeforeInstall: params.NPM_CLEAN_CACHE,

      // 仓库认证
      npmRegistry            : params.NPM_REGISTRY,
      npmRegistryCredentialsId : params.NPM_REGISTRY_AUTH,

      // npm 特性
      legacyPeerDeps         : params.NPM_LEGACY_PEER_DEPS,
      npmAudit               : params.NPM_AUDIT,
    )
  }
}

