steps {
  script {
    // 获取当前任务名
    def jobName = env.JOB_BASE_NAME ?: (env.JOB_NAME ?: 'unknown-job').tokenize('/').last()

    // 获取用户传入的根目录，如果没有则默认为 JENKINS_HOME
    def baseSonarDir = params.SONAR_USER_HOME?.trim()
    if (!baseSonarDir) {
      baseSonarDir = env.JENKINS_HOME
    }

    // 统一拼接子路径，确保一定包含 jobName
    def resolvedSonarUserHome = "${baseSonarDir}/sonar-cache/${jobName}"

    def result = sonarScanVue(
      targetDir: params.SONAR_TARGET_DIR,
      sourcesDir: params.SONAR_SOURCES_DIR,
      sonarHostUrl: params.SONAR_HOST_URL,
      credentialsId: params.SONAR_CREDENTIALS_ID,
      projectKey: params.SONAR_PROJECT_KEY,
      projectVersion: env.BUILD_NUMBER ?: '',
      exclusions: params.SONAR_EXCLUSIONS,
      sonarUserHome: resolvedSonarUserHome,
      wsTimeout: (params.SONAR_WS_TIMEOUT ?: '30') as Integer,
      timeoutMinutes: (params.SONAR_TIMEOUT_MINUTES ?: '20') as Integer,
      tests: params.SONAR_TESTS,
      testInclusions: params.SONAR_TEST_INCLUSIONS,
      coverageExclusions: params.SONAR_COVERAGE_EXCLUSIONS,
      lcovReportPaths: params.SONAR_LCOV_REPORT_PATHS,
      tsconfigPaths: params.SONAR_TSCONFIG_PATHS,
      extraProperties: params.SONAR_EXTRA_PROPERTIES
    )

  }
}

steps {
  cleanWs()  // 清理工作空间
}

steps {
  input message: params.CHECK_PROMPT_MESSAGE, ok: params.CHECK_OK_BUTTON_TEXT
}

success {
  script {
    def scriptContent = params.POST_SUCCESS_SCRIPT
    // 直接执行整个多行脚本（sh 会逐行执行）
    sh scriptContent
  }
}

failure {
  script {
    def scriptContent = params.POST_FAILURE_SCRIPT
    // 直接执行整个多行脚本
    sh scriptContent
  }
}

